import { create } from 'zustand'

function renameInTree(nodes, id, newName) {
    return nodes.map(node =>
        node.id === id
            ? { ...node, name: newName }
            : { ...node, children: node.children ? renameInTree(node.children, id, newName) : node.children }
    );
}

const useTreeStore = create((set) => ({
    treeData: [],
    expandedIds: {},
    setTreeData: (data) => set(() => ({
        treeData: data
    })),
    setExpandedIds: (id) => set((state) => ({
        expandedIds: {
            ...state.expandedIds,
            [id]: !state.expandedIds[id]
        }
    })),
    renameNode: (id, newName) => set((state) => ({
        treeData: renameInTree(state.treeData, id, newName)
    }))
}))


export default useTreeStore
